import re

def parse_duration(s: str) -> int:
    if not s:
        return 0
    units = {'d': 86400, 'h': 3600, 'm': 60, 's': 1}
    total = 0
    for num, unit in re.findall(r'(\d+)\s*([dhms])', s):
        total += int(num) * units[unit]
    return total
